            AND ends_at <= ?2
            AND ${maintenanceCursorVisibilitySql}
        `,
      )
      .bind(opts.cursor, opts.now)
      .first<MaintenanceHistoryCursorRow>();

    if (!cursorRow || typeof cursorRow.ends_at !== 'number') {
      return {
        maintenance_windows: [],
        next_cursor: null,
      };
    }

    seekCursor = cursorRow;
  }
