      opts.trace.setLabel('homepage_guard_state_refresh_reason', cached.source);
      opts.trace.setLabel('homepage_guard_state', 'refresh');
    }
    const refreshed = await readHomepageScheduledFastGuardState(
      opts.db,
      opts.now,
      includeHiddenMonitors,
      opts.trace,
    );
